css:
.ifitwala-print.student-profile {
  --ink: #17212b;
  --muted: #667085;
  --accent: #204a5d;
  --accent-soft: #eef5f7;
  --line: #d7dde3;
  --soft-line: #ebeff3;
  --warning: #8a3b12;
  --highlight: #b9843b;
  color: var(--ink);
  font-family: "Avenir Next", "Helvetica Neue", Arial, sans-serif;
  font-size: 11px;
  line-height: 1.5;
}

.ifitwala-print.student-profile,
.ifitwala-print.student-profile * {
  box-sizing: border-box;
}

.ifitwala-print.student-profile .masthead {
  position: relative;
  margin-bottom: 18px;
  border: 1px solid var(--line);
  background: linear-gradient(135deg, #f9fbfc 0%, #ffffff 64%);
  overflow: hidden;
}

.ifitwala-print.student-profile .brand-ribbon {
  height: 7px;
  background: linear-gradient(90deg, var(--accent) 0%, var(--highlight) 100%);
}

.ifitwala-print.student-profile .masthead-inner {
  display: table;
  width: 100%;
  padding: 16px 18px;
}

.ifitwala-print.student-profile .brand-mark,
.ifitwala-print.student-profile .brand-block,
.ifitwala-print.student-profile .doc-meta {
  display: table-cell;
  vertical-align: top;
}

.ifitwala-print.student-profile .brand-mark {
  width: 88px;
  padding-right: 16px;
}

.ifitwala-print.student-profile .brand-mark img,
.ifitwala-print.student-profile .brand-mark__fallback {
  width: 64px;
  height: 64px;
  border-radius: 16px;
  border: 1px solid rgba(32, 74, 93, 0.14);
  background: #fff;
}

.ifitwala-print.student-profile .brand-mark img {
  object-fit: contain;
  padding: 8px;
}

.ifitwala-print.student-profile .brand-mark__fallback {
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--accent);
  font-family: Baskerville, Georgia, serif;
  font-size: 18px;
  font-weight: 700;
  letter-spacing: 0.08em;
}

.ifitwala-print.student-profile .brand-block {
  width: 100%;
}

.ifitwala-print.student-profile .doc-meta {
  width: 30%;
  text-align: right;
}

.ifitwala-print.student-profile .eyebrow,
.ifitwala-print.student-profile .hero-kicker,
.ifitwala-print.student-profile .section-title,
.ifitwala-print.student-profile .hero-label,
.ifitwala-print.student-profile .info-key,
.ifitwala-print.student-profile .meta-key,
.ifitwala-print.student-profile .premium-table th,
.ifitwala-print.student-profile .crm-panel__eyebrow,
.ifitwala-print.student-profile .contact-chip__label,
.ifitwala-print.student-profile .address-card__meta {
  color: var(--muted);
  font-size: 8.75px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  background: transparent;
  border: none;
  outline: none;
  box-shadow: none;
}

.ifitwala-print.student-profile h1,
.ifitwala-print.student-profile h2 {
  margin: 0;
  color: #0f1720;
  font-family: Baskerville, Georgia, serif;
  font-weight: 600;
}

.ifitwala-print.student-profile h1 {
  font-size: 24px;
  margin-top: 1px;
}

.ifitwala-print.student-profile h2 {
  font-size: 24px;
  line-height: 1.15;
}

.ifitwala-print.student-profile .brand-tagline,
.ifitwala-print.student-profile .subtle,
.ifitwala-print.student-profile .preferred-name,
.ifitwala-print.student-profile .hero-subtitle,
.ifitwala-print.student-profile .crm-panel__subtle {
  color: var(--muted);
  font-size: 10px;
}

.ifitwala-print.student-profile .brand-tagline {
  margin-top: 4px;
  font-size: 10.5px;
  letter-spacing: 0.02em;
}

.ifitwala-print.student-profile .subtle,
.ifitwala-print.student-profile .preferred-name,
.ifitwala-print.student-profile .hero-subtitle {
  margin-top: 6px;
}

.ifitwala-print.student-profile .hero-subtitle span + span::before {
  content: "•";
  margin: 0 7px;
  color: rgba(102, 112, 133, 0.55);
}

.ifitwala-print.student-profile .meta-row {
  margin-bottom: 7px;
}

.ifitwala-print.student-profile .meta-value,
.ifitwala-print.student-profile .hero-value,
.ifitwala-print.student-profile .info-value,
.ifitwala-print.student-profile .contact-chip__value,
.ifitwala-print.student-profile .address-card__title,
.ifitwala-print.student-profile .crm-panel__title {
  color: var(--ink);
}

.ifitwala-print.student-profile .status-pill {
  display: inline-block;
  min-width: 84px;
  padding: 3px 10px;
  border: 1px solid var(--line);
  border-radius: 999px;
  text-align: center;
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.ifitwala-print.student-profile .status-pill.active {
  color: var(--accent);
  background: rgba(32, 74, 93, 0.06);
}

.ifitwala-print.student-profile .status-pill.inactive {
  color: var(--warning);
  background: rgba(138, 59, 18, 0.06);
}

.ifitwala-print.student-profile .hero-card,
.ifitwala-print.student-profile .section-card {
  page-break-inside: avoid;
  break-inside: avoid;
  border: 1px solid var(--line);
  background: linear-gradient(180deg, rgba(248, 250, 251, 0.95), #ffffff 34px);
}

.ifitwala-print.student-profile .hero-card {
  display: table;
  width: 100%;
  margin-bottom: 18px;
}

.ifitwala-print.student-profile .hero-main,
.ifitwala-print.student-profile .hero-image {
  display: table-cell;
  vertical-align: top;
  padding: 18px 20px;
}

.ifitwala-print.student-profile .hero-image {
  width: 128px;
  text-align: right;
}

.ifitwala-print.student-profile .hero-image img {
  width: 86px;
  height: 108px;
  object-fit: cover;
  border: 1px solid var(--line);
  background: #fff;
  box-shadow: 0 10px 20px rgba(23, 33, 43, 0.08);
}

.ifitwala-print.student-profile .hero-grid {
  margin-top: 16px;
  margin-right: 8px;
}

.ifitwala-print.student-profile .hero-item {
  display: inline-block;
  width: 49%;
  margin-bottom: 12px;
  padding-right: 12px;
  vertical-align: top;
}

.ifitwala-print.student-profile .hero-label,
.ifitwala-print.student-profile .meta-key {
  margin-bottom: 2px;
}

.ifitwala-print.student-profile .section-grid {
  margin: 0 -1.2%;
}

.ifitwala-print.student-profile .section-grid::after {
  content: "";
  display: table;
  clear: both;
}

.ifitwala-print.student-profile .section-grid .section-card {
  float: left;
  width: 47.6%;
  margin: 0 1.2% 18px;
}

.ifitwala-print.student-profile .section-card {
  margin-bottom: 18px;
  padding: 14px 16px 12px;
}

.ifitwala-print.student-profile .section-card.wide-card {
  width: 100%;
}

.ifitwala-print.student-profile .section-title {
  margin-bottom: 12px;
  padding-bottom: 7px;
  border-bottom: 1px solid var(--line);
}

.ifitwala-print.student-profile .info-table {
  width: 100%;
}

.ifitwala-print.student-profile .info-row {
  display: grid;
  grid-template-columns: 37% 1fr;
  column-gap: 14px;
  align-items: center;
  padding: 6px 0;
  border-bottom: 1px solid var(--soft-line);
}

.ifitwala-print.student-profile .info-row:last-child {
  border-bottom: none;
}

.ifitwala-print.student-profile .info-key,
.ifitwala-print.student-profile .info-value {
  display: block;
  margin: 0;
  padding: 0;
  border: none;
  outline: none;
  box-shadow: none;
}

.ifitwala-print.student-profile .compact-table {
  margin-bottom: 10px;
}

.ifitwala-print.student-profile .crm-card {
  background: linear-gradient(135deg, rgba(32, 74, 93, 0.05), #ffffff 36%);
}

.ifitwala-print.student-profile .crm-grid {
  display: table;
  width: 100%;
}

.ifitwala-print.student-profile .crm-panel {
  display: table-cell;
  width: 50%;
  vertical-align: top;
  padding-right: 16px;
}

.ifitwala-print.student-profile .crm-panel + .crm-panel {
  padding-left: 16px;
  padding-right: 0;
  border-left: 1px solid var(--soft-line);
}

.ifitwala-print.student-profile .crm-panel__title {
  margin-top: 5px;
  font-family: Baskerville, Georgia, serif;
  font-size: 18px;
  line-height: 1.2;
}

.ifitwala-print.student-profile .crm-panel__subtle {
  margin-top: 4px;
}

.ifitwala-print.student-profile .contact-list,
.ifitwala-print.student-profile .address-stack {
  margin-top: 12px;
}

.ifitwala-print.student-profile .contact-chip,
.ifitwala-print.student-profile .address-card {
  margin-bottom: 10px;
  padding: 9px 10px;
  border: 1px solid var(--soft-line);
  background: rgba(255, 255, 255, 0.82);
}

.ifitwala-print.student-profile .contact-chip__label,
.ifitwala-print.student-profile .address-card__meta {
  display: block;
  margin-bottom: 4px;
}

.ifitwala-print.student-profile .contact-chip__value,
.ifitwala-print.student-profile .address-card__title {
  font-size: 11px;
  font-weight: 600;
}

.ifitwala-print.student-profile .address-card__title {
  font-family: Baskerville, Georgia, serif;
  font-size: 16px;
}

.ifitwala-print.student-profile .address-lines {
  margin-top: 6px;
}

.ifitwala-print.student-profile .crm-empty {
  padding: 10px 0 2px;
  color: var(--muted);
}

.ifitwala-print.student-profile .premium-table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 6px;
}

.ifitwala-print.student-profile .premium-table th {
  padding: 7px 8px;
  border-bottom: 1px solid var(--line);
  text-align: left;
}

.ifitwala-print.student-profile .premium-table td {
  padding: 9px 8px;
  border-bottom: 1px solid var(--soft-line);
  vertical-align: top;
}

.ifitwala-print.student-profile .premium-table tbody tr:last-child td {
  border-bottom: none;
}

.ifitwala-print.student-profile .notes-body {
  color: var(--ink);
  white-space: normal;
  line-height: 1.6;
}

.ifitwala-print.student-profile .exit-card {
  border-color: rgba(138, 59, 18, 0.28);
  background: linear-gradient(180deg, rgba(138, 59, 18, 0.05), #ffffff 34px);
}

@media print {
  .ifitwala-print.student-profile .hero-label,
  .ifitwala-print.student-profile .info-key,
  .ifitwala-print.student-profile .meta-key {
    border: none !important;
    outline: none !important;
    box-shadow: none !important;
    background: transparent !important;
    border-radius: 0 !important;
  }
}

html:
{% set full_name = doc.student_full_name %}
{% if not full_name %}
	{% set full_name = ((doc.student_first_name or "") ~ " " ~ (doc.student_middle_name or "") ~ " " ~ (doc.student_last_name or "")).strip() %}
{% endif %}
{% set full_name = full_name or doc.name %}
{% set preferred_name = (doc.student_preferred_name or "").strip() %}
{% set is_active = 1 if doc.enabled else 0 %}
{% set generated_on = frappe.utils.formatdate(frappe.utils.nowdate()) %}
{% set school_meta = frappe.get_cached_value("School", doc.anchor_school, ["school_name", "school_logo", "school_tagline"], as_dict=True) if doc.anchor_school else None %}
{% set brand_name = school_meta.school_name if school_meta and school_meta.school_name else (doc.get_formatted('anchor_school') if doc.anchor_school else "Ifitwala Ed") %}
{% set brand_logo = school_meta.school_logo if school_meta and school_meta.school_logo else "" %}
{% set brand_tagline = ((school_meta.school_tagline if school_meta and school_meta.school_tagline else "") or "").strip() %}
{% set contact_name = frappe.db.get_value("Dynamic Link", {"link_doctype": "Student", "link_name": doc.name, "parenttype": "Contact"}, "parent") %}
{% set contact_doc = frappe.get_doc("Contact", contact_name) if contact_name else None %}
{% set contact_full_name = (((contact_doc.first_name or "") ~ " " ~ (contact_doc.last_name or "")).strip()) if contact_doc else "" %}
{% set contact_email_rows = frappe.get_all("Contact Email", filters={"parent": contact_name}, fields=["email_id", "is_primary", "idx"], order_by="is_primary desc, idx asc, creation asc") if contact_name else [] %}
{% set contact_phone_rows = frappe.get_all("Contact Phone", filters={"parent": contact_name}, fields=["phone", "is_primary_mobile_no", "idx"], order_by="is_primary_mobile_no desc, idx asc, creation asc") if contact_name else [] %}
{% set address_link_rows = frappe.get_all("Dynamic Link", filters={"parenttype": "Address", "link_doctype": "Student", "link_name": doc.name}, fields=["parent"], order_by="creation asc") %}
{% set address_names = address_link_rows | map(attribute='parent') | list %}
{% set address_docs = frappe.get_all("Address", filters={"name": ["in", address_names]}, fields=["name", "address_title", "address_type", "address_line1", "address_line2", "city", "state", "country", "pincode"], order_by="creation asc") if address_names else [] %}
{% set address_map = {} %}
{% for row in address_docs %}
	{% set _ = address_map.update({row.name: row}) %}
{% endfor %}

<div class="ifitwala-print student-profile">
	<div class="masthead">
		<div class="brand-ribbon"></div>
		<div class="masthead-inner">
			<div class="brand-mark">
				{% if brand_logo %}
				<img src="{{ frappe.utils.escape_html(brand_logo) }}" alt="{{ frappe.utils.escape_html(brand_name) }}">
				{% else %}
				<div class="brand-mark__fallback">SP</div>
				{% endif %}
			</div>
			<div class="brand-block">
				<div class="eyebrow">{{ frappe.utils.escape_html(brand_name) }}</div>
				<h1>Student Profile</h1>
				{% if brand_tagline %}
				<div class="brand-tagline">{{ frappe.utils.escape_html(brand_tagline) }}</div>
				{% endif %}
				<div class="subtle">Generated on {{ frappe.utils.escape_html(generated_on) }}</div>
			</div>
			<div class="doc-meta">
				<div class="meta-row">
					<div class="meta-key">Record</div>
					<div class="meta-value">{{ frappe.utils.escape_html(doc.name) }}</div>
				</div>
				{% if doc.student_id %}
				<div class="meta-row">
					<div class="meta-key">Student ID</div>
					<div class="meta-value">{{ frappe.utils.escape_html(doc.student_id) }}</div>
				</div>
				{% endif %}
				<div class="meta-row">
					<div class="meta-key">Status</div>
					<div class="meta-value">
						<span class="status-pill {{ 'active' if is_active else 'inactive' }}">{{ 'Active' if is_active else 'Inactive' }}</span>
					</div>
				</div>
			</div>
		</div>
	</div>

	<div class="hero-card">
		<div class="hero-main">
			<div class="hero-kicker">Student</div>
			<h2>{{ frappe.utils.escape_html(full_name) }}</h2>
			{% if preferred_name and preferred_name != full_name %}
			<div class="preferred-name">Preferred name: {{ frappe.utils.escape_html(preferred_name) }}</div>
			{% endif %}
			<div class="hero-subtitle">
				{% if doc.anchor_school %}<span>{{ frappe.utils.escape_html(doc.get_formatted('anchor_school')) }}</span>{% endif %}
				{% if brand_tagline %}<span>{{ frappe.utils.escape_html(brand_tagline) }}</span>{% endif %}
			</div>

			<div class="hero-grid">
				{% if doc.anchor_school %}
				<div class="hero-item">
					<div class="hero-label">Anchor School</div>
					<div class="hero-value">{{ frappe.utils.escape_html(doc.get_formatted('anchor_school')) }}</div>
				</div>
				{% endif %}
				{% if doc.cohort %}
				<div class="hero-item">
					<div class="hero-label">Cohort</div>
					<div class="hero-value">{{ frappe.utils.escape_html(doc.get_formatted('cohort')) }}</div>
				</div>
				{% endif %}
				{% if doc.student_house %}
				<div class="hero-item">
					<div class="hero-label">House</div>
					<div class="hero-value">{{ frappe.utils.escape_html(doc.get_formatted('student_house')) }}</div>
				</div>
				{% endif %}
				{% if doc.student_joining_date %}
				<div class="hero-item">
					<div class="hero-label">Joining Date</div>
					<div class="hero-value">{{ frappe.utils.escape_html(doc.get_formatted('student_joining_date')) }}</div>
				</div>
				{% endif %}
			</div>
		</div>
		{% if doc.student_image %}
		<div class="hero-image">
			<img src="{{ frappe.utils.escape_html(doc.student_image) }}" alt="{{ frappe.utils.escape_html(full_name) }}">
		</div>
		{% endif %}
	</div>

	<div class="section-grid">
		<div class="section-card">
			<div class="section-title">Personal</div>
			<div class="info-table">
				{% if doc.student_date_of_birth %}
				<div class="info-row">
					<div class="info-key">Date of Birth</div>
					<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('student_date_of_birth')) }}</div>
				</div>
				{% endif %}
				{% if doc.student_gender %}
				<div class="info-row">
					<div class="info-key">Gender</div>
					<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('student_gender')) }}</div>
				</div>
				{% endif %}
				{% if doc.student_email %}
				<div class="info-row">
					<div class="info-key">Email</div>
					<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('student_email')) }}</div>
				</div>
				{% endif %}
				{% if doc.student_mobile_number %}
				<div class="info-row">
					<div class="info-key">Mobile Number</div>
					<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('student_mobile_number')) }}</div>
				</div>
				{% endif %}
			</div>
		</div>

		<div class="section-card">
			<div class="section-title">Identity and Language</div>
			<div class="info-table">
				{% if doc.student_nationality %}
				<div class="info-row">
					<div class="info-key">Nationality</div>
					<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('student_nationality')) }}</div>
				</div>
				{% endif %}
				{% if doc.student_second_nationality %}
				<div class="info-row">
					<div class="info-key">Second Nationality</div>
					<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('student_second_nationality')) }}</div>
				</div>
				{% endif %}
				{% if doc.student_first_language %}
				<div class="info-row">
					<div class="info-key">First Language</div>
					<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('student_first_language')) }}</div>
				</div>
				{% endif %}
				{% if doc.student_second_language %}
				<div class="info-row">
					<div class="info-key">Second Language</div>
					<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('student_second_language')) }}</div>
				</div>
				{% endif %}
				{% if doc.residency_status %}
				<div class="info-row">
					<div class="info-key">Residency Status</div>
					<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('residency_status')) }}</div>
				</div>
				{% endif %}
			</div>
		</div>
	</div>

	{% if contact_name or address_names %}
	<div class="section-card wide-card crm-card">
		<div class="section-title">Contact and Address</div>
		<div class="crm-grid">
			{% if contact_name %}
			<div class="crm-panel">
				<div class="crm-panel__eyebrow">Linked Contact</div>
				<div class="crm-panel__title">{{ frappe.utils.escape_html(contact_full_name or contact_name) }}</div>
				{% if contact_full_name and contact_full_name != contact_name %}
				<div class="crm-panel__subtle">{{ frappe.utils.escape_html(contact_name) }}</div>
				{% endif %}
				<div class="contact-list">
					{% if contact_email_rows %}
						{% for row in contact_email_rows %}
						<div class="contact-chip">
							<span class="contact-chip__label">{{ "Primary Email" if row.is_primary else "Email" }}</span>
							<span class="contact-chip__value">{{ frappe.utils.escape_html(row.email_id or "") }}</span>
						</div>
						{% endfor %}
					{% endif %}
					{% if contact_phone_rows %}
						{% for row in contact_phone_rows %}
						<div class="contact-chip">
							<span class="contact-chip__label">{{ "Primary Phone" if row.is_primary_mobile_no else "Phone" }}</span>
							<span class="contact-chip__value">{{ frappe.utils.escape_html(row.phone or "") }}</span>
						</div>
						{% endfor %}
					{% endif %}
					{% if not contact_email_rows and not contact_phone_rows %}
					<div class="crm-empty">No email or phone rows are linked to this contact.</div>
					{% endif %}
				</div>
			</div>
			{% endif %}

			{% if address_names %}
			<div class="crm-panel">
				<div class="crm-panel__eyebrow">Linked Address{% if address_names|length > 1 %}es{% endif %}</div>
				<div class="address-stack">
					{% for address_name in address_names %}
					{% set address = address_map.get(address_name) %}
					{% if address %}
					<div class="address-card">
						<div class="address-card__title">{{ frappe.utils.escape_html((address.address_title or address.name or "").strip()) }}</div>
						{% if address.address_type %}
						<div class="address-card__meta">{{ frappe.utils.escape_html(address.address_type) }}</div>
						{% endif %}
						<div class="address-lines">
							{% if address.address_line1 %}<div>{{ frappe.utils.escape_html(address.address_line1) }}</div>{% endif %}
							{% if address.address_line2 %}<div>{{ frappe.utils.escape_html(address.address_line2) }}</div>{% endif %}
							{% if address.city or address.state or address.pincode %}
							<div>{{ frappe.utils.escape_html(((address.city or "") ~ (", " if address.city and address.state else "") ~ (address.state or "") ~ (" " if (address.city or address.state) and address.pincode else "") ~ (address.pincode or "")).strip()) }}</div>
							{% endif %}
							{% if address.country %}<div>{{ frappe.utils.escape_html(address.country) }}</div>{% endif %}
						</div>
					</div>
					{% endif %}
					{% endfor %}
				</div>
			</div>
			{% endif %}
		</div>
	</div>
	{% endif %}

	{% if doc.account_holder or (doc.guardians and doc.guardians|length) %}
	<div class="section-card wide-card">
		<div class="section-title">Family</div>
		{% if doc.account_holder %}
		<div class="info-table compact-table">
			<div class="info-row">
				<div class="info-key">Account Holder</div>
				<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('account_holder')) }}</div>
			</div>
		</div>
		{% endif %}
		{% if doc.guardians and doc.guardians|length %}
		<table class="premium-table guardians-table">
			<thead>
				<tr>
					<th>Guardian</th>
					<th>Relation</th>
					<th>Authorized Signer</th>
					<th>Phone</th>
					<th>Email</th>
				</tr>
			</thead>
			<tbody>
				{% for row in doc.guardians %}
				<tr>
					<td>{{ frappe.utils.escape_html(row.guardian_name or row.guardian or '') }}</td>
					<td>{{ frappe.utils.escape_html(row.relation or '') }}</td>
					<td>{{ 'Yes' if row.can_consent else 'No' }}</td>
					<td>{{ frappe.utils.escape_html(row.phone or '') }}</td>
					<td>{{ frappe.utils.escape_html(row.email or '') }}</td>
				</tr>
				{% endfor %}
			</tbody>
		</table>
		{% endif %}
	</div>
	{% endif %}

	{% if doc.siblings and doc.siblings|length %}
	<div class="section-card wide-card">
		<div class="section-title">Siblings</div>
		<table class="premium-table siblings-table">
			<thead>
				<tr>
					<th>Sibling Name</th>
					<th>Gender</th>
					<th>Date of Birth</th>
				</tr>
			</thead>
			<tbody>
				{% for row in doc.siblings %}
				<tr>
					<td>{{ frappe.utils.escape_html(row.sibling_name or row.student or '') }}</td>
					<td>{{ frappe.utils.escape_html(row.sibling_gender or '') }}</td>
					<td>{% if row.sibling_date_of_birth %}{{ frappe.utils.escape_html(frappe.utils.formatdate(row.sibling_date_of_birth)) }}{% endif %}</td>
				</tr>
				{% endfor %}
			</tbody>
		</table>
	</div>
	{% endif %}

	{% if doc.additional_comment %}
	<div class="section-card wide-card notes-card">
		<div class="section-title">Additional Comment</div>
		<div class="notes-body">{{ frappe.utils.escape_html(doc.additional_comment).replace('\n', '<br>') | safe }}</div>
	</div>
	{% endif %}

	{% if not is_active %}
	<div class="section-card wide-card exit-card">
		<div class="section-title">Exit Information</div>
		<div class="info-table">
			{% if doc.student_exit_date %}
			<div class="info-row">
				<div class="info-key">Exit Date</div>
				<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('student_exit_date')) }}</div>
			</div>
			{% endif %}
			{% if doc.student_exit_reason %}
			<div class="info-row">
				<div class="info-key">Exit Reason</div>
				<div class="info-value">{{ frappe.utils.escape_html(doc.get_formatted('student_exit_reason')) }}</div>
			</div>
			{% endif %}
		</div>
	</div>
	{% endif %}
</div>
